  const cMatch = color.match(/rgba?\((\d+),\s*(\d+),\s*(\d+)/);
  const bMatch = bg.match(/rgba?\((\d+),\s*(\d+),\s*(\d+)/);
  if (!cMatch || !bMatch) continue;
  const [r1,g1,b1] = [parseInt(cMatch[1]), parseInt(cMatch[2]), parseInt(cMatch[3])];
  const [r2,g2,b2] = [parseInt(bMatch[1]), parseInt(bMatch[2]), parseInt(bMatch[3])];
  // Relative luminance
  const lum = (c) => { const v = c/255; return v <= 0.03928 ? v/12.92 : Math.pow((v+0.055)/1.055, 2.4); };
  const L1 = 0.2126*lum(r1)+0.7152*lum(g1)+0.0722*lum(b1);
  const L2 = 0.2126*lum(r2)+0.7152*lum(g2)+0.0722*lum(b2);
  const ratio = (Math.max(L1,L2)+0.05)/(Math.min(L1,L2)+0.05);
  if (ratio < 3.0 && text.length > 10) {
    issues.push({ratio: ratio.toFixed(2), text: text.substring(0,50), tag: el.tagName, color, bg});
  }
}
issues.sort((a,b) => a.ratio - b.ratio).slice(0,15).map(i => `RATIO ${i.ratio} | ${i.tag} | "${i.text}" | fg:${i.color} bg:${i.bg}`)
"}

