)
print(f"Token verify: {r.json().get('success')}")

# Get zone
r = requests.get(
    f"https://api.cloudflare.com/client/v4/zones/{ZONE_ID}",
    headers={"Authorization": f"Bearer {token}"}
)
print(f"Zone access: {r.status_code} — {r.json().get('success')}")

# Check existing records
r = requests.get(
    f"https://api.cloudflare.com/client/v4/zones/{ZONE_ID}/dns_records?name=dayah.paragu-ai.com",
    headers={"Authorization": f"Bearer {token}"}
)
existing = r.json().get("result", [])
print(f"Existing records: {len(existing)}")
for rec in existing:
